if (str_contains($relationName, '.')) {
    // Nested relations
    $relations = explode('.', $relationName);

    foreach ($relations as $relation) {
        $result = $closure($calledOnType, $relation, $node);

        if ($result !== []) {
            return $result;
        }

        $modelReflection = $this->modelRuleHelper->findModelReflectionFromType($calledOnType);

        if ($modelReflection === null) {
            return [];
        }

        // Dynamic method return type extensions are not taken into account here.
        // So we simulate a method call to the relation here to get the return type.
        $calledOnType = $scope->getType(new MethodCall(new Node\Expr\New_(new Node\Name($modelReflection->getName())), new Node\Identifier($relation)));
    }

    return [];
}

trait CanGenerateGetHeaderActionsMethod
{
    protected function addGetHeaderActionsMethodToClass(ClassType $class): void
    {
        $actions = array_map(
            fn (string $action): string => (string) new Literal("{$this->simplifyFqn($action)}::make(),"),
            $this->getHeaderActions(),
        );

        $actionsOutput = implode(PHP_EOL . '    ', $actions);

        $method = $class->addMethod('getHeaderActions')
            ->setProtected()
            ->setReturnType('array')
            ->setBody(
                <<<PHP
                return [
                    {$actionsOutput}
                ];
                PHP
            );

        $this->configureGetHeaderActionsMethod($method);
    }

    protected function configureGetHeaderActionsMethod(Method $method): void {}
}

