foreach (Arr::wrap($this->evaluate($this->components)) as $componentIndex => $component) {
    if ($component instanceof Action) {
        $this->modifyAction($component);
    }

    if ($component instanceof ActionGroup) {
        $this->modifyActionGroup($component);
    }

    if (($component instanceof Action) || ($component instanceof ActionGroup)) {
        $component = $component->schemaContainer($this);
        $components[$componentIndex] = $component;

        continue;
    }

    if (is_string($component)) {
        $component = Text::make($component);
    }

    if (! $component instanceof Component) {
        $component = Html::make($component);
    }

    $component = $component->container($this);
    $components[$componentIndex] = $component;
}

if (is_string($package)) {
    $oldClass = 'AnourValar\EloquentSerialize\Package';
    $newClass = Package::class;

    // Replace the class reference in the serialized object header (`O:36:"..."`)
    $package = str_replace(
        'O:' . strlen($oldClass) . ':"' . $oldClass . '"',
        'O:' . strlen($newClass) . ':"' . $newClass . '"',
        $package,
    );

    // Replace the class prefix in serialized private properties (`s:42:"\0...\0data"`)
    $package = str_replace(
        's:' . (strlen($oldClass) + 6) . ':"' . "\0" . $oldClass . "\0" . 'data"',
        's:' . (strlen($newClass) + 6) . ':"' . "\0" . $newClass . "\0" . 'data"',
        $package,
    );

    $package = unserialize($package);
}

try {
    foreach ($table->getFilters() as $filter) {
        $filter->applyToBaseQuery(
            $query,
            $this->getTableFilterState($filter->getName()) ?? [],
        );
    }

    return $query->where(function (Builder $query) use ($table, $isResolvingRecord): void {
        foreach ($table->getFilters() as $filter) {
            if ($isResolvingRecord && $filter->shouldExcludeWhenResolvingRecord()) {
                continue;
            }

            $filter->apply(
                $query,
                $this->getTableFilterState($filter->getName()) ?? [],
            );
        }
    });
} finally {
    if ($table->hasDeferredFilters()) {
        $filtersForm = $this->getTableFiltersForm()->statePath('tableDeferredFilters');

        $filtersForm->flushCachedAbsoluteStatePaths();
        $filtersForm->clearCachedDefaultChildSchemas();
