}

foreach ($node->params as $param) {
    if ((! $param->type) || (! $this->isName($param->type, Schema::class))) {
        continue;
    }
    $expectedName = $this->expectedNameResolver->resolveForParamIfNotYet($param);
    if ($expectedName === null) {
        continue;
    }
    if ($this->shouldSkipParam($param, $expectedName, $node)) {
        continue;
    }
    $expectedName = $this->matchParamTypeExpectedNameResolver->resolve($param);
    if ($expectedName === null) {
        continue;
    }
    $paramRename = $this->paramRenameFactory->createFromResolvedExpectedName($node, $param, $expectedName);
    if (! $paramRename instanceof ParamRename) {
        continue;
    }
    $this->paramRenamer->rename($paramRename);
    $this->hasChanged = \true;
}

foreach ($fillable as $key => $value) {
    // The developers may choose to place some attributes in the "fillable" array
    // which means only those attributes may be set through mass assignment to
    // the model, and all others will just get ignored for security reasons.
    if ($this->isFillable($key)) {
        $this->setAttribute($key, $value);
    } elseif ($totallyGuarded || static::preventsSilentlyDiscardingAttributes()) {
        if (isset(static::$discardedAttributeViolationCallback)) {
            call_user_func(static::$discardedAttributeViolationCallback, $this, [$key]);
        } else {
            throw new MassAssignmentException(sprintf(
                'Add [%s] to fillable property to allow mass assignment on [%s].',
                $key, get_class($this)
            ));
        }
    }
}

if (is_string($firstComponent) && ! class_exists($firstComponent)) {
    // Simple component name (eg. `counter`)
    $id = $firstComponent;
    $components = [$firstComponent, ...$components];
} else {
    if (is_string($firstComponent)) {
        // Component class name (eg. `App\Livewire\Counter`)
        $className = $firstComponent;
    } else {
        // Anonymous class instance (eg. `new class extends Component {}`)
        // Remove the runtime '$123' suffix to make the class name stable
        $className = str()->beforeLast($firstComponent::class, '$');
    }

    // A string ID that can be used in the URL
    $id = 'a' . substr(md5($className), 0, 8);
    $components = [$id => $firstComponent, ...$components];
}

if (count($ruleKeys)) {
    $ruleKey = $ruleKeys->shift();
    $fieldKey = $fieldKeys->shift();

    if ($fieldKey == '*') {
        // If the specified field has a '*', then loop through the collection and keep the whole collection intact.
        foreach ($data as $key => $value) {
            $data[$key] = $this->filterCollectionDataDownToSpecificKeys($value, $ruleKeys, $fieldKeys);
        }
    } else {
        // Otherwise filter collection down to a specific key
        $keyData = data_get($data, $fieldKey, null);

        if ($ruleKey == '*') {
            $data = [];
        }

        data_set($data, $fieldKey, $this->filterCollectionDataDownToSpecificKeys($keyData, $ruleKeys, $fieldKeys));
    }
}

if (array_key_exists($scopeName, $reflection->getMethodTags())) {
    $methodTag = $reflection->getMethodTags()[$scopeName];

    $parameters = [];
    foreach ($methodTag->getParameters() as $parameterName => $parameterTag) {
        $parameters[] = new AnnotationScopeMethodParameterReflection(
            $parameterName,
            $parameterTag->getType(),
            $parameterTag->passedByReference(),
            $parameterTag->isOptional(),
            $parameterTag->isVariadic(),
            $parameterTag->getDefaultValue(),
        );
    }

    // We shift the parameters,
    // because first parameter is the Builder
    array_shift($parameters);

    return new EloquentBuilderMethodReflection(
        $scopeName,
        $reflection,
        $parameters,
        $methodTag->getReturnType(),
    );
}

if ($builderReflection->hasNativeMethod($methodName)) {
    $reflection = $builderReflection->getNativeMethod($methodName);

    $parametersAcceptor = $this->transformStaticParameters($reflection, $genericBuilderAndModelType);

    $returnType = TypeTraverser::map($parametersAcceptor->getReturnType(), static function (Type $type, callable $traverse) use ($genericBuilderAndModelType) {
        if ($type instanceof TypeWithClassName && $type->getClassName() === Builder::class) {
            return $genericBuilderAndModelType;
        }

        return $traverse($type);
    });

    return new EloquentBuilderMethodReflection(
        $methodName,
        $builderReflection,
        $parametersAcceptor->getParameters(),
        $returnType,
        $parametersAcceptor->isVariadic(),
    );
}

